const body = $input.item.json.body || $input.item.json || {};
const file = $input.item.binary?.file || $input.item.binary?.data;
const source = body.source || 'import';
const importId = body.import_batch_id || body.import_id || body.quote_id || `IMP_${Date.now()}`;
const jobId = body.job_id || `job_${Date.now()}`;

const successUrl = body.callbackSuccessUrl || body.callbacks?.success_url;
const failedUrl = body.callbackFailedUrl || body.callbacks?.failed_url;

if (!successUrl) {
  throw new Error("Missing callbackSuccessUrl in webhook payload!");
}

const filename = file?.fileName || file?.name || body.filename || 'document.pdf';
const rawMime = (file?.mimeType || file?.mimetype || '').toLowerCase();
const extIsPdf = filename.toLowerCase().endsWith('.pdf');

// Accept application/pdf, application/octet-stream with .pdf ext, or any missing mime with .pdf ext
const isPdf = rawMime === 'application/pdf' || extIsPdf || rawMime.includes('pdf');
const mimeType = isPdf ? 'application/pdf' : (rawMime || 'unknown');

return {
  json: {
    importId,
    jobId,
    filename,
    mime_type: mimeType,
    is_pdf: isPdf,
    callbackSuccessUrl: successUrl,
    callbackFailedUrl: failedUrl,
    source,
    source_format: 'pdf'
  },
  binary: $input.item.binary
};

const meta = $("Metadata & Validation2").first().json;
let extractedRows = [];
let errorMessage = null;

try {
  let rawText = $("OpenAI Assistants API").first().json.choices[0].message.content;
  if (rawText.includes("```json")) {
     rawText = rawText.replace(/```json/g, "").replace(/```/g, "").trim();
  }
  console.log('raw:', rawText);
  const parsed = JSON.parse(rawText);
  extractedRows = Array.isArray(parsed) ? parsed : (parsed.rows || []);
} catch(e) {
  errorMessage = "Ошибка обработки ИИ: " + e.message + ". Возможно, текст слишком большой или файл поврежден.";
}

if (!errorMessage && (!extractedRows || extractedRows.length === 0)) {
  errorMessage = "Не удалось распознать товарные позиции. Убедитесь, что файл содержит список товаров, или что текст (кодировка) читаем, а не зашифрован как картинка.";
}

if (errorMessage) {
  return {
    json: {
      import_batch_id: meta.importId,
      job_id: meta.jobId,
      status: "failed",
      error: errorMessage,
      callbackFailedUrl: meta.callbackFailedUrl
    }
  };
}

return {
  json: {
    import_batch_id: meta.importId,
    job_id: meta.jobId,
    status: "parsed",
    rows: extractedRows,
    callbackSuccessUrl: meta.callbackSuccessUrl
  }
};

return {
  json: {
    import_batch_id: $input.item.json.importId,
    job_id: $input.item.json.jobId,
    status: "failed",
    error: "Неподдерживаемый формат: " + $input.item.json.mime_type + ". Загрузите PDF-файл.",
    callbackFailedUrl: $input.item.json.callbackFailedUrl
  }
};

const meta = .first().json;
const openaiKey = $("Inject API Key").first().json.openaiKey;
if (!openaiKey) throw new Error("Missing OPENAI_API_KEY");

const binaryData = await this.helpers.getBinaryDataBuffer(0, 'file');
const fileName = .item.binary.file.fileName || 'document.pdf';

const boundary = '----WebKitFormBoundary7MA4YWxkTrZu0gW';
const header = `--${boundary}
Content-Disposition: form-data; name="purpose"

assistants
--${boundary}
Content-Disposition: form-data; name="file"; filename="${fileName}"
Content-Type: application/pdf

`;
const footer = `
--${boundary}--
`;

const body = Buffer.concat([
  Buffer.from(header, 'utf8'),
  binaryData,
  Buffer.from(footer, 'utf8')
]);

let uploadRes;
try {
  const result = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.openai.com/v1/files',
    headers: {
      'Authorization': `Bearer ${openaiKey}`,
      'Content-Type': `multipart/form-data; boundary=${boundary}`
    },
    body: body,
    encoding: null 
  });
  uploadRes = typeof result === 'string' ? JSON.parse(result) : result;
} catch(e) {
  throw new Error("File upload failed: " + (e.message || e));
}

const fileId = uploadRes.id;
let assistantId = null;

try {
  const prompt = `You are a master data extractor. Extract all items from the attached document into a JSON object. Ensure the format is exactly {"rows": [ { "name": "...", "article": "...", "qty": 1, "purchase_price": 100, "volume_l": 0.75, "country": "...", "category": "...", "note": "..." } ] }. Respond ONLY with a valid JSON object.`;

  const assistantResStr = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.openai.com/v1/assistants',
    headers: {
      'Authorization': `Bearer ${openaiKey}`,
      'OpenAI-Beta': 'assistants=v2',
      'Content-Type': 'application/json'
    },
    body: {
      name: 'PDF Extractor Temp',
      model: 'gpt-4o',
      instructions: prompt,
      tools: [{ type: "file_search" }],
      tool_resources: { file_search: { vector_stores: [{ file_ids: [fileId] }] } }
    }
  });
  const assistantRes = typeof assistantResStr === 'string' ? JSON.parse(assistantResStr) : assistantResStr;
  assistantId = assistantRes.id;

  const runResStr = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.openai.com/v1/threads/runs',
    headers: {
      'Authorization': `Bearer ${openaiKey}`,
      'OpenAI-Beta': 'assistants=v2',
      'Content-Type': 'application/json'
    },
    body: {
      assistant_id: assistantId,
      response_format: { type: "json_object" }
    }
  });
  const runRes = typeof runResStr === 'string' ? JSON.parse(runResStr) : runResStr;

  const threadId = runRes.thread_id;
  let runId = runRes.id;

  let status = runRes.status;
  while (status === "queued" || status === "in_progress") {
    await new Promise(r => setTimeout(r, 4000));
    const pollResStr = await this.helpers.httpRequest({
      method: 'GET',
      url: `https://api.openai.com/v1/threads/${threadId}/runs/${runId}`,
      headers: {
        'Authorization': `Bearer ${openaiKey}`,
        'OpenAI-Beta': 'assistants=v2'
      }
    });
    const pollRes = typeof pollResStr === 'string' ? JSON.parse(pollResStr) : pollResStr;
    status = pollRes.status;
    if (status === "failed") throw new Error(`Run failed`);
  }

  const msgsResStr = await this.helpers.httpRequest({
    method: 'GET',
    url: `https://api.openai.com/v1/threads/${threadId}/messages`,
    headers: {
      'Authorization': `Bearer ${openaiKey}`,
      'OpenAI-Beta': 'assistants=v2'
    }
  });
  const msgsRes = typeof msgsResStr === 'string' ? JSON.parse(msgsResStr) : msgsResStr;

  await this.helpers.httpRequest({ method: 'DELETE', url: `https://api.openai.com/v1/assistants/${assistantId}`, headers: {'Authorization': `Bearer ${openaiKey}`, 'OpenAI-Beta': 'assistants=v2'} }).catch(()=>{});
  await this.helpers.httpRequest({ method: 'DELETE', url: `https://api.openai.com/v1/files/${fileId}`, headers: {'Authorization': `Bearer ${openaiKey}`} }).catch(()=>{});

  const contentBlock = msgsRes.data[0].content.find(c => c.type === 'text');
  let rawText = contentBlock ? contentBlock.text.value : '{"rows":[]}';

  return { json: { choices: [ { message: { content: rawText } } ] } };

} catch(e) {
  if (assistantId) await this.helpers.httpRequest({ method: 'DELETE', url: `https://api.openai.com/v1/assistants/${assistantId}`, headers: {'Authorization': `Bearer ${openaiKey}`, 'OpenAI-Beta': 'assistants=v2'} }).catch(()=>{});
  await this.helpers.httpRequest({ method: 'DELETE', url: `https://api.openai.com/v1/files/${fileId}`, headers: {'Authorization': `Bearer ${openaiKey}`} }).catch(()=>{});
  throw e;
}

